package com.plsrflttr.controllers;

import com.plsrflttr.dto.RoomDto;
import com.plsrflttr.dto.WorkplaceDto;
import com.plsrflttr.services.RoomsService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequiredArgsConstructor
@RequestMapping("/api/rooms")
public class RoomsController {
    private final RoomsService roomsService;

    @GetMapping("/{room_id}")
    public RoomDto getRoom() {
        return ResponseEntity.status(HttpStatus.OK).body(roomsService.getRoom("")).getBody();
    }

    @GetMapping("/{room_id}/workplaces")
    public List<WorkplaceDto> getWorkplaces(@PathVariable String room_id) {
        return ResponseEntity.status(HttpStatus.OK).body(roomsService.getWorkplaces(room_id)).getBody();
    }

}

package com.plsrflttr.controllers;

import com.plsrflttr.dto.RoomDto;
import com.plsrflttr.dto.WorkplaceDto;
import com.plsrflttr.services.RoomsService;
import lombok.RequiredArgsConstructor;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequiredArgsConstructor
@RequestMapping("/api/rooms")
public class RoomsController {
    private final RoomsService roomsService;

    @GetMapping("/{room_id}")
    public RoomDto getRoom(@PathVariable String room_id) {
        return roomsService.getRoom(room_id);
    }

    @GetMapping("/{room_id}/workplaces")
    public List<WorkplaceDto> getWorkplaces(@PathVariable String room_id) {
        return roomsService.getWorkplaces(room_id);
    }

}
